async function handleCallback(query) {
  const chatId = query.from.id;
  const msgId = query.message.message_id;
  const cbData = query.data;

  if (!isAdmin(chatId)) {
    await api('answerCallbackQuery', { callback_query_id: query.id, text: '⛔ Not authorized', show_alert: true });
    return;
  }
  await api('answerCallbackQuery', { callback_query_id: query.id });

  if (cbData === 'adm_dash') {
    const today = new Date().toISOString().slice(0, 10);
    const todayCount = db.users.filter(u => u.joined === today).length;
    await api('sendMessage', {
      chat_id: chatId,
      text: `📊 *Dashboard*\n\n👥 Total subscribers: *${db.users.length}*\n📅 Joined today: *${todayCount}*\n🔔 Notifications: *${db.notificationsEnabled ? 'ON ✅' : 'OFF ❌'}*\n🏪 Shop: *${(db.config?.shopOpen !== false) ? 'OPEN ✅' : 'CLOSED ❌'}*\n📦 Orders: *${db.orders?.length || 0}*\n\n🏪 Shop: \`${db.links.shop}\``,
      parse_mode: 'Markdown'
    });

  } else if (cbData === 'adm_users') {
    if (db.users.length === 0) {
      await api('sendMessage', { chat_id: chatId, text: '👥 No subscribers yet.' });
      return;
    }
    let chunk = '👥 *Subscribers:*\n\n';
    const chunks = [];
    for (const u of db.users) {
      const line = `• ${u.name}${u.username ? ' ' + u.username : ''} — \`${u.id}\` — ${u.joined}\n`;
      if (chunk.length + line.length > 4000) { chunks.push(chunk); chunk = ''; }
      chunk += line;
    }
    if (chunk) chunks.push(chunk);
    for (const c of chunks) await api('sendMessage', { chat_id: chatId, text: c, parse_mode: 'Markdown' });

  } else if (cbData === 'adm_editwelcome') {
    adminState[chatId] = 'awaiting_welcome';
    await api('sendMessage', {
      chat_id: chatId,
      text: `📝 *Current welcome message:*\n\n${db.welcome}\n\n✏️ Send the new welcome message now. Markdown is supported.\n\nSend /cancel to abort.`,
      parse_mode: 'Markdown'
    });

  } else if (cbData === 'adm_togglenotif') {
    db.notificationsEnabled = !db.notificationsEnabled;
    saveData();
    await api('editMessageReplyMarkup', { chat_id: chatId, message_id: msgId, reply_markup: adminKeyboard(db.notificationsEnabled) });
    await api('sendMessage', { chat_id: chatId, text: `🔔 Notifications: *${db.notificationsEnabled ? 'ON ✅' : 'OFF ❌'}*`, parse_mode: 'Markdown' });

  } else if (cbData === 'adm_broadcast') {
    adminState[chatId] = 'awaiting_broadcast';
    await api('sendMessage', {
      chat_id: chatId,
      text: `📣 *Broadcast Message*\n\n${db.users.length} subscribers will receive this.\n\n✏️ Type your message now. Markdown is supported.\n\nSend /cancel to abort.`,
      parse_mode: 'Markdown'
    });

  } else if (cbData === 'adm_links') {
    const l = db.links;
    await api('sendMessage', {
      chat_id: chatId,
      text: `🔗 *Current Links:*\n\n🏪 shop: \`${l.shop}\`\n📸 instagram: \`${l.instagram}\`\n💬 contact: \`${l.contact}\``,
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [
          [{ text: '🏪 Edit Shop URL', callback_data: 'adm_link_shop' }],
          [{ text: '📸 Edit Instagram', callback_data: 'adm_link_instagram' }, { text: '💬 Edit Contact', callback_data: 'adm_link_contact' }]
        ]
      }
    });

  } else if (cbData.startsWith('adm_link_')) {
    const key = cbData.replace('adm_link_', '');
    adminState[chatId] = { action: 'awaiting_link_url', key };
    await api('sendMessage', {
      chat_id: chatId,
      text: `🔗 Editing *${key}* link.\n\nCurrent: \`${db.links[key]}\`\n\nSend the new URL now.\n\nSend /cancel to abort.`,
      parse_mode: 'Markdown'
    });

  } else if (cbData === 'adm_ids') {
    const ids = db.users.map(u => u.id).join(', ');
    await api('sendMessage', {
      chat_id: chatId,
      text: `🆔 *All Chat IDs* (${db.users.length} total):\n\n\`${ids || 'None yet'}\`\n\n📥 To import IDs, send:\n\`/importids 123456,789012,345678\``,
      parse_mode: 'Markdown'
    });

  // ── ⚙️ CONFIGURATION ────────────────────────────────────────────────────────
  } else if (cbData === 'adm_config') {
    if (!db.config) db.config = { shopOpen: true, autoReply: true, closedMessage: '⛔ Shop is temporarily closed. Check back soon!' };
    const { shopOpen, autoReply, closedMessage } = db.config;
    await api('sendMessage', {
      chat_id: chatId,
      text: `⚙️ *Configuration*\n\n🏪 Shop: *${shopOpen ? 'OPEN ✅' : 'CLOSED ❌'}*\n💬 Auto-reply: *${autoReply ? 'ON ✅' : 'OFF ❌'}*\n\n📝 Closed message:\n_${closedMessage}_`,
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [
          [{ text: `🏪 Shop: ${shopOpen ? 'OPEN ✅' : 'CLOSED ❌'}`, callback_data: 'adm_cfg_shop' }],
          [{ text: `💬 Auto-reply: ${autoReply ? 'ON ✅' : 'OFF ❌'}`, callback_data: 'adm_cfg_autoreply' }],
          [{ text: '✏️ Edit Closed Message', callback_data: 'adm_cfg_closedmsg' }]
        ]
      }
    });

  } else if (cbData === 'adm_cfg_shop') {
    if (!db.config) db.config = { shopOpen: true, autoReply: true, closedMessage: '⛔ Shop is temporarily closed. Check back soon!' };
    db.config.shopOpen = !db.config.shopOpen;
    saveData();
    await api('sendMessage', { chat_id: chatId, text: `🏪 Shop is now *${db.config.shopOpen ? 'OPEN ✅' : 'CLOSED ❌'}*`, parse_mode: 'Markdown' });

  } else if (cbData === 'adm_cfg_autoreply') {
    if (!db.config) db.config = { shopOpen: true, autoReply: true, closedMessage: '⛔ Shop is temporarily closed. Check back soon!' };
    db.config.autoReply = !db.config.autoReply;
    saveData();
    await api('sendMessage', { chat_id: chatId, text: `💬 Auto-reply is now *${db.config.autoReply ? 'ON ✅' : 'OFF ❌'}*`, parse_mode: 'Markdown' });

  } else if (cbData === 'adm_cfg_closedmsg') {
    adminState[chatId] = 'awaiting_closed_msg';
    await api('sendMessage', {
      chat_id: chatId,
      text: `✏️ Current closed message:\n\n_${db.config?.closedMessage}_\n\nSend the new message now.\n\nSend /cancel to abort.`,
      parse_mode: 'Markdown'
    });

  // ── 📦 COMMANDES ────────────────────────────────────────────────────────────
  } else if (cbData === 'adm_orders') {
    if (!db.orders || db.orders.length === 0) {
      await api('sendMessage', {
        chat_id: chatId,
        text: `📦 *Commandes*\n\nNo orders yet.\n\n📝 To add an order:\n\`/neworder CustomerName | Product | Notes\``,
        parse_mode: 'Markdown'
      });
      return;
    }
    const icon = { pending: '⏳', processing: '🔄', shipped: '📦', done: '✅' };
    let text = `📦 *Commandes* (${db.orders.length} total):\n\n`;
    for (const o of db.orders.slice(-20).reverse()) {
      text += `${icon[o.status] || '⏳'} *#${o.id}* — ${o.customer} — ${o.product} — _${o.date}_\n`;
    }
    text += `\n📝 \`/neworder Name | Product | Notes\` to add\n📋 \`/orderstatus ID\` to manage`;
    await api('sendMessage', { chat_id: chatId, text, parse_mode: 'Markdown' });

  } else if (cbData.startsWith('o_') && cbData.split('_').length === 3) {
    const parts = cbData.split('_');
    const action = parts[1];
    const oid = parseInt(parts[2]);
    const order = (db.orders || []).find(o => o.id === oid);
    if (!order) { await api('sendMessage', { chat_id: chatId, text: '❌ Order not found.' }); return; }
    const statusMap = { p: 'pending', c: 'processing', s: 'shipped', d: 'done' };
    if (action === 'x') {
      db.orders = db.orders.filter(o => o.id !== oid);
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `🗑️ Order *#${oid}* deleted.`, parse_mode: 'Markdown' });
    } else if (statusMap[action]) {
      order.status = statusMap[action];
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `✅ Order *#${oid}* → *${order.status}*`, parse_mode: 'Markdown', reply_markup: orderStatusKeyboard(oid) });
    }

  // ── 🔄 ACTIONS RAPIDES ──────────────────────────────────────────────────────
  } else if (cbData === 'adm_quickactions') {
    await api('sendMessage', {
      chat_id: chatId,
      text: '🔄 *Actions Rapides*\n\nChoose an action:',
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [
          [{ text: '🔁 Reset Image Cache', callback_data: 'adm_qa_resetcache' }],
          [{ text: '📤 Send Menu to All Users', callback_data: 'adm_qa_sendmenu' }],
          [{ text: '🗑️ Remove User by ID', callback_data: 'adm_qa_rmuser' }],
          [{ text: '✅ Ping Bot', callback_data: 'adm_qa_ping' }]
        ]
      }
    });

  } else if (cbData === 'adm_qa_resetcache') {
    cachedFileId = null;
    await api('sendMessage', { chat_id: chatId, text: '🔁 Image cache cleared. Photo will re-upload on next send.' });

  } else if (cbData === 'adm_qa_sendmenu') {
    const targets = [...db.users];
    await api('sendMessage', { chat_id: chatId, text: `📤 Sending menu to ${targets.length} users...` });
    let ok = 0, fail = 0;
    for (const user of targets) {
      try { await sendWithPhoto(user.id, db.welcome); ok++; } catch(e) { fail++; }
      await new Promise(r => setTimeout(r, 80));
    }
    await api('sendMessage', { chat_id: chatId, text: `✅ Done!\n✔️ Sent: ${ok}\n✖️ Failed: ${fail}` });

  } else if (cbData === 'adm_qa_rmuser') {
    adminState[chatId] = 'awaiting_remove_user';
    await api('sendMessage', { chat_id: chatId, text: '🗑️ Send the Telegram ID of the user to remove.\n\nSend /cancel to abort.' });

  } else if (cbData === 'adm_qa_ping') {
    const up = process.uptime();
    const h = Math.floor(up / 3600), m = Math.floor((up % 3600) / 60), s = Math.floor(up % 60);
    await api('sendMessage', {
      chat_id: chatId,
      text: `✅ *Bot online!*\n\n⏱️ Uptime: ${h}h ${m}m ${s}s\n👥 Users: ${db.users.length}\n📦 Orders: ${db.orders?.length || 0}\n🔔 Notifications: ${db.notificationsEnabled ? 'ON' : 'OFF'}\n🏪 Shop: ${(db.config?.shopOpen !== false) ? 'OPEN' : 'CLOSED'}`,
      parse_mode: 'Markdown'
    });

  // ── 📈 RAPPORTS ─────────────────────────────────────────────────────────────
  } else if (cbData === 'adm_reports') {
    const today = new Date();
    const days = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - i);
      const key = d.toISOString().slice(0, 10);
      const count = db.users.filter(u => u.joined === key).length;
      days.push({ key: key.slice(5), count });
    }
    const chart = days.map(d => `${d.key}: ${'█'.repeat(Math.min(d.count, 10)) || '·'} ${d.count}`).join('\n');
    const history = (db.broadcastHistory || []).slice(-5).reverse()
      .map(b => `• ${b.date} — "${b.text.slice(0, 28)}…" → ${b.ok} sent`)
      .join('\n') || 'No broadcasts yet.';
    await api('sendMessage', {
      chat_id: chatId,
      text: `📈 *Rapports*\n\n📅 *Signups — last 7 days:*\n\`\`\`\n${chart}\n\`\`\`\n\n📣 *Broadcast history:*\n${history}\n\n👥 Total users: ${db.users.length}\n📦 Total orders: ${db.orders?.length || 0}`,
      parse_mode: 'Markdown'
    });
  }
}

async function handleMessage(msg) {
  const chatId = msg.chat.id;
  const from = msg.from;
  const text = msg.text || '';
  const name = from?.first_name || 'there';

  trackUser(from);
  console.log(`[${new Date().toISOString().slice(11, 19)}] ${name} (${chatId}): ${text}`);

  if (isAdmin(chatId) && adminState[chatId]) {
    if (text === '/cancel') {
      delete adminState[chatId];
      await api('sendMessage', { chat_id: chatId, text: '❌ Cancelled.' });
      return;
    }
    const s = adminState[chatId];

    if (s === 'awaiting_welcome') {
      delete adminState[chatId];
      db.welcome = text;
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `✅ Welcome message updated!\n\nPreview:\n\n${text}`, parse_mode: 'Markdown' });
      return;
    }

    if (s === 'awaiting_broadcast') {
      delete adminState[chatId];
      const targets = [...db.users];
      await api('sendMessage', { chat_id: chatId, text: `📣 Sending to ${targets.length} users...` });
      let ok = 0, fail = 0;
      for (const user of targets) {
        try { await api('sendMessage', { chat_id: user.id, text, parse_mode: 'Markdown' }); ok++; }
        catch(e) { fail++; }
        await new Promise(r => setTimeout(r, 50));
      }
      if (!db.broadcastHistory) db.broadcastHistory = [];
      db.broadcastHistory.push({ text, date: new Date().toISOString().slice(0, 10), ok, fail });
      if (db.broadcastHistory.length > 50) db.broadcastHistory = db.broadcastHistory.slice(-50);
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `✅ Broadcast done!\n✔️ Delivered: ${ok}\n✖️ Failed: ${fail}` });
      return;
    }

    if (s?.action === 'awaiting_link_url') {
      const key = s.key;
      delete adminState[chatId];
      if (!text.startsWith('http')) {
        await api('sendMessage', { chat_id: chatId, text: '❌ Invalid URL. Must start with https://' });
        return;
      }
      db.links[key] = text;
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `✅ *${key}* updated!\n\`${text}\``, parse_mode: 'Markdown' });
      return;
    }

    if (s === 'awaiting_closed_msg') {
      delete adminState[chatId];
      if (!db.config) db.config = { shopOpen: true, autoReply: true, closedMessage: '' };
      db.config.closedMessage = text;
      saveData();
      await api('sendMessage', { chat_id: chatId, text: `✅ Closed message updated!` });
      return;
    }

    if (s === 'awaiting_remove_user') {
      delete adminState[chatId];
      const uid = parseInt(text.trim());
      if (isNaN(uid)) { await api('sendMessage', { chat_id: chatId, text: '❌ Invalid ID.' }); return; }
      const before = db.users.length;
      db.users = db.users.filter(u => u.id !== uid);
      saveData();
      await api('sendMessage', { chat_id: chatId, text: db.users.length < before ? `✅ User ${uid} removed.` : `❌ User ${uid} not found.` });
      return;
    }
  }

  if (isAdmin(chatId) && text === '/admin') {
    await sendAdminMenu(chatId);
    return;
  }

  if (isAdmin(chatId) && text.startsWith('/importids')) {
    const raw = text.replace('/importids', '').trim();
    const ids = raw.split(/[\s,]+/).map(s => parseInt(s)).filter(n => !isNaN(n));
    let added = 0;
    for (const id of ids) {
      if (!db.users.find(u => u.id === id)) {
        db.users.push({ id, name: 'Imported', username: '', joined: new Date().toISOString().slice(0, 10) });
        added++;
      }
    }
    saveData();
    await api('sendMessage', { chat_id: chatId, text: `✅ Imported *${added}* new IDs. Total: ${db.users.length}`, parse_mode: 'Markdown' });
    return;
  }

  if (isAdmin(chatId) && text.startsWith('/neworder')) {
    const raw = text.replace('/neworder', '').trim();
    const parts = raw.split('|').map(p => p.trim());
    if (parts.length < 2) {
      await api('sendMessage', { chat_id: chatId, text: '❌ Format: `/neworder CustomerName | Product | Notes`', parse_mode: 'Markdown' });
      return;
    }
    if (!db.orders) db.orders = [];
    db.nextOrderId = (db.nextOrderId || 0) + 1;
    const order = { id: db.nextOrderId, customer: parts[0], product: parts[1], notes: parts[2] || '', status: 'pending', date: new Date().toISOString().slice(0, 10) };
    db.orders.push(order);
    saveData();
    await api('sendMessage', {
      chat_id: chatId,
      text: `✅ Order *#${order.id}* added!\n\n👤 ${order.customer}\n📦 ${order.product}\n📝 ${order.notes || '—'}\n⏳ Status: pending`,
      parse_mode: 'Markdown',
      reply_markup: orderStatusKeyboard(order.id)
    });
    return;
  }

  if (isAdmin(chatId) && text.startsWith('/orderstatus')) {
    const oid = parseInt(text.replace('/orderstatus', '').trim());
    const order = (db.orders || []).find(o => o.id === oid);
    if (!order) { await api('sendMessage', { chat_id: chatId, text: `❌ Order #${oid} not found.` }); return; }
    const icon = { pending: '⏳', processing: '🔄', shipped: '📦', done: '✅' };
    await api('sendMessage', {
      chat_id: chatId,
      text: `📦 *Order #${order.id}*\n\n👤 ${order.customer}\n📦 ${order.product}\n📝 ${order.notes || '—'}\n${icon[order.status] || '⏳'} Status: *${order.status}*\n📅 ${order.date}`,
      parse_mode: 'Markdown',
      reply_markup: orderStatusKeyboard(order.id)
    });
    return;
  }

  if (text.startsWith('/start') || text.startsWith('/menu')) {
    if (!isAdmin(chatId) && db.config?.shopOpen === false) {
      await api('sendMessage', { chat_id: chatId, text: db.config.closedMessage || '⛔ Shop is temporarily closed.' });
    } else {
      await sendWithPhoto(chatId, db.welcome);
    }
  } else if (db.notificationsEnabled && db.config?.autoReply !== false) {
    await sendWithPhoto(chatId, `Hey ${name}! 👋 Use the menu below 👇`);
  }
}

async function sendWithPhoto(chatId, caption) {
  const KEYBOARD = buildKeyboard();
  if (cachedFileId) {
    const r = await api('sendPhoto', {
      chat_id: chatId, photo: cachedFileId,
      caption, parse_mode: 'Markdown', reply_markup: KEYBOARD
    });
    if (r.ok) return r;
    console.error('Cached photo send failed:', r.description);
    cachedFileId = null;
  }
  try {
    const imgBuffer = Buffer.from(IMG_B64, 'base64');
    const res = await apiMultipart('sendPhoto', {
      chat_id: chatId, caption,
      parse_mode: 'Markdown', reply_markup: JSON.stringify(KEYBOARD)
    }, imgBuffer, 'mountaingiants.jpg');
    if (res.ok && res.result?.photo) {
      cachedFileId = res.result.photo[res.result.photo.length - 1].file_id;
      console.log('Image cached:', cachedFileId);
      return res;
    }
    console.error('Photo upload failed:', JSON.stringify(res));
  } catch(e) {
    console.error('Photo upload error:', e.message);
  }
  return await api('sendMessage', {
    chat_id: chatId, text: caption,
    parse_mode: 'Markdown', reply_markup: KEYBOARD
  });
}

let offset = 0;

async function poll() {
  try {
    const res = await api('getUpdates', { offset, timeout: 30, limit: 100, allowed_updates: ['message', 'callback_query'] });
    if (res.ok && res.result?.length) {
      for (const update of res.result) {
        offset = update.update_id + 1;
        if (update.callback_query) {
          await handleCallback(update.callback_query);
        } else if (update.message?.text) {
          await handleMessage(update.message);
        }
      }
    }
  } catch(e) { console.error('Poll error:', e.message); }
  setTimeout(poll, 1500);
}

async function start() {
  try {
    await api('deleteWebhook', { drop_pending_updates: true });
    const me = await api('getMe', {});
    console.log(`Bot running: @${me.result?.username}`);
    await api('setMyCommands', { commands: [
      { command: 'start', description: '🏔️ Open Mountain Giants menu' },
      { command: 'menu', description: '📋 Show all options' }
    ]});
    await api('setChatMenuButton', { menu_button: {
      type: 'web_app', text: '🏪 Shop',
      web_app: { url: db.links.shop }
    }});
    console.log('Ready — polling...');
    if (ADMIN_ID) await api('sendMessage', { chat_id: ADMIN_ID, text: '✅ Bot started! Send /admin to open the admin panel.' });
    poll();
  } catch(e) {
    console.error('Startup error:', e.message);
    setTimeout(start, 5000);
  }
}

start();
